//! Stepwise analysis cards — JSON shape aligned with
//! `gnosis-math` `StepwiseAnalysisFramework.AnalysisCard` / `FrfStep` /
//! `TwinVoidDial` (Lean `Nat` fields map to `u64` here for serde stability).
//!
//! Feed an `analysis_run` on [`crate::swarm::ManifoldInput`] so the chaos
//! manifold XOR-mixes a deterministic digest into the PRNG seed before
//! `tick_monte_carlo`, keeping the engine deterministic given `(seed, run)`.

use serde::{Deserialize, Serialize};

/// Five FRF operations + sliver — matches Lean `StepwiseAnalysisFramework.FrfStep`.
#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq, Hash)]
#[serde(rename_all = "camelCase")]
pub enum FrfStep {
    Fork,
    Race,
    Fold,
    Vent,
    Sliver,
}

/// Twin-void dial (rim, structural void, consensus fill).
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq, Hash)]
#[serde(rename_all = "camelCase")]
pub struct TwinVoidDial {
    pub rim: u64,
    pub void_structural: u64,
    pub consensus_fill: u64,
}

/// One step in a formal analysis run (Lean `AnalysisCard`).
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq, Hash)]
#[serde(rename_all = "camelCase")]
pub struct AnalysisCard {
    pub phase: FrfStep,
    /// Ladder world-level; values above 10 are clamped for digest mixing.
    pub world_level: u32,
    pub seq: u64,
    pub twin_dial: Option<TwinVoidDial>,
    pub budget: Option<u64>,
    pub vent_amt: Option<u64>,
}

#[inline(always)]
fn phase_tag(p: FrfStep) -> u64 {
    match p {
        FrfStep::Fork => 0,
        FrfStep::Race => 1,
        FrfStep::Fold => 2,
        FrfStep::Vent => 3,
        FrfStep::Sliver => 4,
    }
}

/// Deterministic 64-bit digest of a run (order-sensitive). XOR’d into the
/// chaos engine seed before Monte Carlo ticks.
pub fn digest_analysis_run(cards: &[AnalysisCard]) -> u64 {
    let mut h: u64 = 0xCB6B_8D09_4F39_91D5;
    for c in cards {
        let wl = (c.world_level as u64).min(10);
        h = h.wrapping_mul(0x9E37_79B9_7F4A_7C15);
        h ^= phase_tag(c.phase);
        h = h.wrapping_add(wl.wrapping_shl(8));
        h ^= c.seq;
        if let Some(ref d) = c.twin_dial {
            h = h.wrapping_add(d.rim ^ d.void_structural ^ d.consensus_fill);
        }
        if let Some(b) = c.budget {
            h ^= b.wrapping_mul(3);
        }
        if let Some(v) = c.vent_amt {
            h ^= v.wrapping_mul(5);
        }
    }
    h
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn digest_stable_on_empty() {
        assert_eq!(digest_analysis_run(&[]), 0xCB6B_8D09_4F39_91D5);
    }

    #[test]
    fn serde_roundtrip_card() {
        let c = AnalysisCard {
            phase: FrfStep::Fold,
            world_level: 10,
            seq: 2,
            twin_dial: Some(TwinVoidDial {
                rim: 5,
                void_structural: 3,
                consensus_fill: 5,
            }),
            budget: Some(100),
            vent_amt: Some(7),
        };
        let j = serde_json::to_string(&c).unwrap();
        let d: AnalysisCard = serde_json::from_str(&j).unwrap();
        assert_eq!(c, d);
    }
}
